const cfg = $('Config').item.json;
const items = $input.all();

function findCheck(type) {
  return (items.find(i => i.json.check_type === type) || { json: {} }).json;
}

const nullR    = findCheck('null_check');
const dupR     = findCheck('dup_check');
const countR   = findCheck('row_count');
const outlierR = findCheck('outlier_check');

function evalStatus(value, threshold, mode) {
  if (mode === 'above') {
    if (value === 0)                                                     return { label: 'PASS', color: '#16a34a' };
    if (value <= threshold)                                              return { label: 'WARN', color: '#d97706' };
    return                                                                      { label: 'FAIL', color: '#dc2626' };
  }
  if (mode === 'range') {
    if (value >= cfg.rowCountMin && value <= cfg.rowCountMax)            return { label: 'PASS', color: '#16a34a' };
    if (value < cfg.rowCountMin * 0.8 || value > cfg.rowCountMax * 1.2) return { label: 'FAIL', color: '#dc2626' };
    return                                                                      { label: 'WARN', color: '#d97706' };
  }
}

const nullPct    = parseFloat(nullR.null_pct       ?? 0);
const dupPct     = parseFloat(dupR.dup_pct         ?? 0);
const rowCount   = parseInt(countR.row_count       ?? 0, 10);
const outlierPct = parseFloat(outlierR.outlier_pct ?? 0);

const checks = [
  { name: 'Null / missing values', col: cfg.nullCheckCol,      value: `${nullPct}%`,              threshold: `< ${cfg.nullThresholdPct}%`,              st: evalStatus(nullPct,    cfg.nullThresholdPct, 'above') },
  { name: 'Duplicate rows',        col: cfg.duplicateCheckCol, value: `${dupPct}%`,               threshold: `< ${cfg.dupThresholdPct}%`,               st: evalStatus(dupPct,     cfg.dupThresholdPct,  'above') },
  { name: 'Row count anomaly',     col: cfg.tableName,         value: rowCount.toLocaleString(),  threshold: `${cfg.rowCountMin} – ${cfg.rowCountMax}`, st: evalStatus(rowCount,   null,                 'range') },
  { name: 'Outlier values',        col: cfg.outlierCol,        value: `${outlierPct}%`,           threshold: `${cfg.outlierMin} – ${cfg.outlierMax}`,  st: evalStatus(outlierPct, 5,                    'above') },
];

const hasFail = checks.some(c => c.st.label === 'FAIL');
const hasWarn = checks.some(c => c.st.label === 'WARN');
const overall = hasFail ? 'FAIL' : hasWarn ? 'WARN' : 'PASS';
const oc      = { PASS: '#16a34a', WARN: '#d97706', FAIL: '#dc2626' }[overall];
const now     = new Date().toISOString().slice(0, 19).replace('T', ' ') + ' UTC';

const badge = (label, color) =>
  `<span style='background:${color}18;color:${color};border:1px solid ${color}40;padding:2px 10px;border-radius:999px;font-size:12px;font-weight:600'>${label}</span>`;

const tableRow = c =>
  `<tr style='border-bottom:1px solid #e5e7eb'>` +
  `<td style='padding:10px 14px'>${c.name}</td>` +
  `<td style='padding:10px 14px;color:#6b7280'>${c.col}</td>` +
  `<td style='padding:10px 14px;font-weight:600'>${c.value}</td>` +
  `<td style='padding:10px 14px;color:#6b7280'>${c.threshold}</td>` +
  `<td style='padding:10px 14px'>${badge(c.st.label, c.st.color)}</td>` +
  `</tr>`;

const htmlReport =
  `<!DOCTYPE html><html><body style='font-family:-apple-system,sans-serif;background:#f9fafb;padding:32px;color:#111827'>` +
  `<div style='max-width:640px;margin:auto;background:white;border-radius:12px;overflow:hidden;box-shadow:0 1px 4px rgba(0,0,0,0.08)'>` +
  `<div style='padding:24px 28px;border-bottom:1px solid #f3f4f6;display:flex;justify-content:space-between;align-items:center'>` +
  `<div>` +
  `<div style='font-size:18px;font-weight:600'>Data Quality Report</div>` +
  `<div style='font-size:13px;color:#9ca3af;margin-top:2px'>Table: <strong style='color:#374151'>${cfg.tableName}</strong> &nbsp;&middot;&nbsp; ${now}</div>` +
  `</div>${badge(overall, oc)}</div>` +
  `<table style='width:100%;border-collapse:collapse;font-size:14px'>` +
  `<thead><tr style='background:#f9fafb;text-align:left'>` +
  `<th style='padding:10px 14px;color:#6b7280;font-weight:500'>Check</th>` +
  `<th style='padding:10px 14px;color:#6b7280;font-weight:500'>Column</th>` +
  `<th style='padding:10px 14px;color:#6b7280;font-weight:500'>Value</th>` +
  `<th style='padding:10px 14px;color:#6b7280;font-weight:500'>Threshold</th>` +
  `<th style='padding:10px 14px;color:#6b7280;font-weight:500'>Status</th>` +
  `</tr></thead>` +
  `<tbody>${checks.map(tableRow).join('')}</tbody>` +
  `</table>` +
  `<div style='padding:16px 28px;background:#f9fafb;font-size:12px;color:#9ca3af'>` +
  `Generated by n8n Data Quality Bot &nbsp;&middot;&nbsp; Thresholds configured in the Config (Set) node` +
  `</div></div></body></html>`;

return [{
  json: {
    overall,
    htmlReport,
    emailSubject: `[${overall}] Data Quality — ${cfg.tableName} — ${now}`,
    reportEmail:  cfg.reportEmail,
    sheet_timestamp:   now,
    sheet_table:       cfg.tableName,
    sheet_null_pct:    nullPct,
    sheet_dup_pct:     dupPct,
    sheet_row_count:   rowCount,
    sheet_outlier_pct: outlierPct,
    sheet_status:      overall
  }
}];
